    this.quoteService = quoteService;
    this.permissionService = permissionService;
    this.quotes = [];
    this.filteredQuotes = [];
    this.loading = true;
    this.error = '';
    this.searchTerm = '';
    this.sortColumn = 'createdAt';
    this.sortDirection = 'desc';
  }
