    this.loadQuotes();
  }
  loadQuotes() {
    this.loading = true;
    this.quoteService.getAllQuotes().subscribe({
      next: quotes => {
        console.log('获取到的询价列表:', quotes);
        console.log('rejected状态的询价:', quotes.filter(q => q.status === 'rejected'));
        // 根据用户权限过滤询价
        const user = this.authService.getCurrentUser();
        if (user) {
          this.quotes = quotes.filter(quote => this.permissionService.canViewQuote(quote, user));
        } else {
          this.quotes = quotes;
        }
        console.log('过滤后的询价列表:', this.quotes);
        this.applyFiltersAndSort();
        this.loading = false;
      },
      error: error => {
        this.error = '加载询价单失败';
        this.loading = false;
        console.error(error);
      }
    });
  }
  applyFiltersAndSort() {
    // 应用搜索过滤
    let filtered = this.quotes;
    if (this.searchTerm.trim()) {
      const searchLower = this.searchTerm.toLowerCase().trim();
      filtered = this.quotes.filter(quote => quote.quoteNumber.toLowerCase().includes(searchLower) || quote.title.toLowerCase().includes(searchLower) || quote.description && quote.description.toLowerCase().includes(searchLower) || quote.customer?.name && quote.customer.name.toLowerCase().includes(searchLower) || quote.quoter?.name && quote.quoter.name.toLowerCase().includes(searchLower) || quote.supplier?.name && quote.supplier.name.toLowerCase().includes(searchLower) || this.getStatusDisplayName(quote.status).toLowerCase().includes(searchLower));
    }
    // 应用排序
    filtered = this.sortQuotes(filtered, this.sortColumn, this.sortDirection);
    this.filteredQuotes = filtered;
  }
  sortQuotes(quotes, column, direction) {
    return [...quotes].sort((a, b) => {
      let aValue;
      let bValue;
      switch (column) {
        case 'quoteNumber':
          aValue = a.quoteNumber;
          bValue = b.quoteNumber;
          break;
        case 'title':
          aValue = a.title;
          bValue = b.title;
          break;
        case 'customer':
          aValue = a.customer?.name || '';
          bValue = b.customer?.name || '';
          break;
        case 'quoter':
          aValue = a.quoter?.name || '';
          bValue = b.quoter?.name || '';
          break;
        case 'supplier':
          aValue = a.supplier?.name || '';
          bValue = b.supplier?.name || '';
          break;
        case 'status':
          aValue = this.getStatusDisplayName(a.status);
          bValue = this.getStatusDisplayName(b.status);
          break;
        case 'createdAt':
          aValue = new Date(a.createdAt);
          bValue = new Date(b.createdAt);
          break;
        default:
          aValue = a[column];
          bValue = b[column];
      }
      if (aValue < bValue) {
        return direction === 'asc' ? -1 : 1;
      }
      if (aValue > bValue) {
        return direction === 'asc' ? 1 : -1;
      }
      return 0;
    });
  }
  onSort(column) {
    if (this.sortColumn === column) {
      this.sortDirection = this.sortDirection === 'asc' ? 'desc' : 'asc';
    } else {
      this.sortColumn = column;
      this.sortDirection = 'asc';
    }
    this.applyFiltersAndSort();
  }
  onSearchChange() {
    this.applyFiltersAndSort();
  }
  getSortIcon(column) {
    if (this.sortColumn !== column) {
      return 'bi bi-arrow-down-up';
    }
    return this.sortDirection === 'asc' ? 'bi bi-arrow-up' : 'bi bi-arrow-down';
  }
  getQuoteCountByStatus(status) {
    return this.quotes.filter(quote => quote.status === status).length;
  }
  canEditQuote(quote) {
    const user = this.authService.getCurrentUser();
    if (!user) return false;
    return this.permissionService.canEditQuote(quote, user);
  }
  canDeleteQuote(quote) {
    const user = this.authService.getCurrentUser();
    if (!user) return false;
    return this.permissionService.canDeleteQuote(quote, user);
  }
  // Expose status utility to template
  getStatusDisplayName(status) {
    return getStatusDisplayName(status);
  }
  deleteQuote(quote) {
    if (confirm(`确定要删除询价单"${quote.title}"吗？此操作不可撤销。`)) {
      this.quoteService.deleteQuote(quote._id).subscribe({
        next: () => {
          // 从列表中移除已删除的询价单
          this.quotes = this.quotes.filter(q => q._id !== quote._id);
          this.applyFiltersAndSort();
        },
        error: error => {
          console.error('删除询价单失败:', error);
          alert('删除询价单失败，请重试');
        }
      });
    }
  }
  navigateToQuoteDetail(quoteId) {
    this.router.navigate(['/quotes', quoteId]);
  }
  downloadFile(quoteId, fileType) {
    // 先获取询价单详情以获取询价单号
